@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;
        var isClickable = isCompleted && !isCurrent;

        <div class="step-item text-center flex-fill position-relative @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(!isCurrent && !isCompleted ? "dimmed" : "")"
             role="button"
             tabindex="@(isClickable ? 0 : -1)"
             @onclick="() => { if (isClickable) OnStepClicked.InvokeAsync(step); }">
            <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
                        @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-secondary text-white")"
                 style="width:36px;height:36px;font-size:0.85rem;">
                @if (isCompleted && !isCurrent)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <small class="@(isCurrent ? "fw-bold" : isCompleted ? "text-success" : "text-muted")">@StepNames[i]</small>
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Reference.Name" placeholder="Full name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Reference.Relationship" placeholder="e.g. Former Manager" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" placeholder="Email address" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" placeholder="Phone number" />
            </div>
        </div>
