@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<h4 class="mb-3">Personal Information</h4>

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control @(Errors.ContainsKey("FullName") ? "is-invalid" : "")"
               @bind="Model.FullName" placeholder="Your full name" />
        @if (Errors.ContainsKey("FullName"))
        {
            <div class="invalid-feedback">@Errors["FullName"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email"
               class="form-control @(Errors.ContainsKey("Email") ? "is-invalid" : "")"
               @bind="Model.Email" placeholder="you@example.com" />
        @if (Errors.ContainsKey("Email"))
        {
            <div class="invalid-feedback">@Errors["Email"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel"
               class="form-control @(Errors.ContainsKey("Phone") ? "is-invalid" : "")"
               @bind="Model.Phone" placeholder="Phone number" />
        @if (Errors.ContainsKey("Phone"))
        {
            <div class="invalid-feedback">@Errors["Phone"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control @(Errors.ContainsKey("Address") ? "is-invalid" : "")"
               @bind="Model.Address" placeholder="Your address" />
        @if (Errors.ContainsKey("Address"))
        {
            <div class="invalid-feedback">@Errors["Address"]</div>
        }
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public bool IsValidating { get; set; }
    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}

@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index + 1"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate is null)
            {
                errorMessage = "Please fill in company, title, and start date for all positions.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   Index="index + 1"
                   CanRemove="References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space:pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
}

@page "/apply"
@using sv_92e22f1886f347e5878749dc5c613cbf.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width:800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              Errors="personalInfoErrors"
                              IsValidating="isValidatingEmail"
                              OnNext="HandlePersonalInfoNext" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => AdvanceTo(3)"
                             OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="() => AdvanceTo(4)"
                            OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="val => coverLetter = val"
