toolArgs.file_text:
@using sv_92e22f1886f347e5878749dc5c613cbf.Models

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space:pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
}

@page "/apply"
@using sv_92e22f1886f347e5878749dc5c613cbf.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width:800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              Errors="personalInfoErrors"
                              IsValidating="isValidatingEmail"
                              OnNext="HandlePersonalInfoNext" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => AdvanceTo(3)"
                             OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="() => AdvanceTo(4)"
                            OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="val => coverLetter = val"
                             OnNext="() => AdvanceTo(5)"
                             OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        OnEditStep="GoToStep"
                        OnSubmit="HandleSubmit"
                        OnBack="() => GoToStep(4)"
                        IsSubmitting="isSubmitting"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    // UI state
    private bool isValidatingEmail;
    private bool isSubmitting;
    private bool isSubmitted;
    private int? applicationId;
    private Dictionary<string, string> personalInfoErrors = new();

    private void GoToStep(int step)
    {
        if (step >= 1 && step <= 5)
            currentStep = step;
    }

    private void AdvanceTo(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private async Task HandlePersonalInfoNext()
    {
        personalInfoErrors.Clear();

        if (string.IsNullOrWhiteSpace(personalInfo.FullName))
            personalInfoErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(personalInfo.Email))
            personalInfoErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(personalInfo.Phone))
            personalInfoErrors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(personalInfo.Address))
            personalInfoErrors["Address"] = "Address is required.";

        if (personalInfoErrors.Count > 0)
            return;

        isValidatingEmail = true;
        StateHasChanged();

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(personalInfo.Email);
            if (!isValid)
            {
                personalInfoErrors["Email"] = "Please enter a valid email address.";
                return;
            }

            AdvanceTo(2);
        }
        finally
        {
            isValidatingEmail = false;
        }
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        StateHasChanged();

        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
            completedSteps.Add(5);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

